/* ================= HELPERS ================= */
const gFmt = n => '$' + n.toLocaleString('en-US');
const STYLE_NAME = {A:'Sit-or-Stand', B:'Pivotal Access', C:'Gammill Original'};
// Retrofit grade pill (era + table style designation).
const catBadge = c => c ? `<button type="button" class="gpl-badge cat" title="See what Category ${c} means — era + table style" onclick="event.stopPropagation();gplCategory('${c}')">Category ${c}</button>` : '';
// Non-retrofit table-style reference pill (points to the table photos/style).
const styleBadge = c => c ? `<button type="button" class="gpl-badge cat" title="See the ${STYLE_NAME[c]||''} table" onclick="event.stopPropagation();gplCategory('${c}')">${c}-style table</button>` : '';
const retroBadge = r => r ? `<span class="gpl-badge retro">Retrofit</span>` : '';

/* ================= RENDER ================= */
function gplUnitRow(u, fi, ui, fam){
  const sold = u.status==='sold';
  const status = sold ? `<span class="gpl-badge sold">Sold</span>` : `<span class="gpl-badge avail">1 available</span>`;
  const region = u.region ? `<div class="gpl-unit-sub" style="color:var(--orange-d);font-weight:600">${u.region}</div>` : '';
  const action = sold
    ? `<button class="gpl-btn gpl-btn--dark gpl-btn--sm" onclick="gplInquiry('Waitlist: ${u.throat}″ ${fam.name} show machine')">Waitlist</button>`
    : `<button class="gpl-btn gpl-btn--primary gpl-btn--sm" onclick="gplBuild(${fi},${ui})">Select Options</button>`;
  return `<div class="gpl-unit ${sold?'sold':''}" data-type="${fam.type}" data-throat="${u.throat}">
    <div>
      <div class="gpl-badges">${u.retrofit?catBadge(u.category):styleBadge(u.category)} ${retroBadge(u.retrofit)} ${status}</div>
      <div class="gpl-unit-title">${u.throat}″ · ${u.year}</div>
      <div class="gpl-unit-sub">${u.table}</div>${region}
    </div>
    <div>
      <div class="gpl-price tnum">${u.price?gFmt(u.price):'—'}</div>
      <div class="gpl-mo tnum">${u.monthly?'from $'+u.monthly+'/mo':''}</div>
    </div>
    <div class="gpl-unit-actions">
      <button class="gpl-btn gpl-btn--ghost gpl-btn--sm" onclick="gplDetail(${fi},${ui})">Details</button>
      ${action}
    </div>
  </div>`;
}

function gplFamily(fam, fi){
  const prices = fam.units.filter(u=>u.price).map(u=>u.price);
  const from = prices.length?Math.min(...prices):null;
  const count = fam.units.filter(u=>u.status!=='sold').length;
  const shared = fam.shared.map(([k,v])=>`<div class="gpl-spec"><dt>${k}</dt><dd>${v}</dd></div>`).join('');
  const incl = fam.included.map(i=>`<li><span class="ck">✓</span>${i}</li>`).join('');
  const rows = fam.units.map((u,ui)=>gplUnitRow(u,fi,ui,fam)).join('');
  return `<article class="gpl-family" id="gpl-fam-${fam.id}" data-type="${fam.type}">
    <div class="gpl-family-grid">
      <div class="gpl-family-story">
        <div class="gpl-fam-img">
          ${fam.image ? `<img src="${fam.image}" alt="${fam.name} longarm — representative photo" loading="lazy">` : `Representative ${fam.name} photo`}
        </div>
        <p class="h-eyebrow" style="margin-bottom:8px">${fam.typeLabel}</p>
        <h3>${fam.name}</h3>
        <p class="gpl-tagline">${fam.tagline}</p>
        <p class="muted" style="margin:0 0 16px">${fam.blurb}</p>
        ${GPL_FEATURES[fam.id] ? `<button class="gpl-btn gpl-btn--ghost gpl-btn--sm" style="margin:0 0 18px" onclick="gplFeatures('${fam.id}')">Review ${fam.name} Features</button>` : ''}
        <dl style="margin:0 0 20px">${shared}</dl>
        <p class="gpl-cap" style="margin:0 0 10px">Every ${fam.name} includes</p>
        <ul class="gpl-incl">${incl}</ul>
      </div>
      <div style="background:#fcfcfc">
        <div class="gpl-units-head">
          <div><span class="gpl-cap">Available now</span> <span class="muted" style="font-size:14px">· ${count} machine${count!==1?'s':''}</span></div>
          ${from?`<div class="muted" style="font-size:13.5px">from <b style="font-family:Raleway;font-weight:800;color:var(--ink);font-size:16px">${gFmt(from)}</b></div>`:''}
        </div>
        <div class="gpl-units">${rows}</div>
        <div class="gpl-units-foot">
          <button class="gpl-link" onclick="gplInquiry('Looking for a ${fam.name} — size/budget in message')">Want a different year or size of ${fam.name}? Tell us →</button>
        </div>
      </div>
    </div>
  </article>`;
}

function gplRenderFamilies(){ document.getElementById('gpl-families').innerHTML = FAMILIES.map((f,i)=>gplFamily(f,i)).join(''); }

function gplRenderHeroStats(){
  const all = FAMILIES.flatMap(f=>f.units).filter(u=>u.status!=='sold');
  const minP = Math.min(...all.filter(u=>u.price).map(u=>u.price));
  const stats = [[all.length,'machines ready to deliver'],['from '+gFmt(minP),'lowest price in stock']];
  document.getElementById('gpl-hero-stats').innerHTML = stats.map(([a,b])=>`<div class="gpl-stat"><b class="tnum">${a}</b><span>${b}</span></div>`).join('');
}

function gplRenderFAQ(){
  document.getElementById('gpl-faqlist').innerHTML = GPL_FAQS.map(([q,a])=>`<details><summary>${q}<span class="pm">+</span></summary><p>${a}</p></details>`).join('');
}

/* ===== TYPE SELECTOR + LINE LISTINGS (simple page) ===== */
function gplRow(u,fi,ui,fam){
  const sold=u.status==='sold';
  const metaLabel=u.retrofit?('Category '+u.category):(''+u.year);
  const brand={vision:'vision',statler:'statler',ascend:'ascend'}[fam.id]||'primary';
  const note=u.region?`<span class="gpl-row-note">${u.region}</span>`:'';
  const tableBtn=u.table?`<button class="gpl-row-meta" onclick="gplPricing(1)" title="See the table styles">${u.table}</button>`:'';
  let action;
  if(sold){
    action=`<button class="gpl-btn gpl-btn--dark gpl-btn--sm" onclick="gplInquiry('Waitlist: ${u.throat}″ ${fam.name}')">Join waitlist</button>`;
  } else {
    // price + /mo ride on top of the configurator button; the action line names the quote outcome
    const priceLine=u.price
      ? `<span class="gpl-quotebtn-price"><span class="gpl-quotebtn-amt tnum">${gFmt(u.price)}</span>${u.monthly?`<span class="gpl-quotebtn-mo tnum">from $${u.monthly}/mo</span>`:''}</span>`
      : `<span class="gpl-quotebtn-price"><span class="gpl-quotebtn-amt">Request price</span></span>`;
    action=`<button class="gpl-quotebtn gpl-quotebtn--${brand}" onclick="gplBuild(${fi},${ui})">
        ${priceLine}
        <span class="gpl-quotebtn-cta">Configure &amp; quote →</span>
      </button>${u.savings?`<span class="gpl-row-save tnum">Save ${gFmt(u.savings)} vs. new</span>`:''}`;
  }
  return `<div class="gpl-row${sold?' sold':''}">
    <div class="gpl-row-id">
      <span class="gpl-row-throat tnum">${u.throat}″</span>
      <span class="gpl-row-model">${fam.name}</span>
      <button class="gpl-row-meta" onclick="gplPricing(0)" title="What the ${u.retrofit?'A/B/C category':'year'} means">${metaLabel}</button>
      ${tableBtn}
      ${note}
    </div>
    <div class="gpl-row-act">${action}</div>
  </div>`;
}
