// Multi-select: render a grouped block (intro + rows) for each checked family.
function gplApplyMachineFilter(){
  const target=document.getElementById('gpl-mlist'); if(!target) return;
  const checked={};
  document.querySelectorAll('input[name="gpl-machine"]:checked').forEach(function(i){ checked[i.value]=true; });
  let html='';
  ['vision','statler','ascend'].forEach(function(m){
    if(!checked[m]) return;
    const fi=FAMILIES.findIndex(f=>f.id===m), fam=FAMILIES[fi], c=GPL_MCFG[m];
    if(!fam) return;
    let rows=''; fam.units.forEach((u,ui)=>{ rows+=gplRow(u,fi,ui,fam); });
    html+=`<div class="gpl-mgroup"><p class="gpl-typepanel-intro">${c.intro} <a href="${c.url}" target="_blank" rel="noopener">${c.link}</a></p>`
        + `<div class="gpl-rows">${rows||'<div class="gpl-row"><span class="muted">None in stock right now.</span></div>'}</div></div>`;
  });
  target.innerHTML = html
    ? `<p class="gpl-row-legend">Tap any underlined term — category, table style, or year — to see what it means.</p>` + html
    : `<p class="gpl-typepanel-intro">Nothing selected — tap a type above to view machines.</p>`;
}

/* ===== Testimonial slider: auto-advance, per-slide delay scales with review length ===== */
function gplInitSlider(){
  var sl=document.getElementById('gpl-slider'); if(!sl) return;
  window.__gplSlides=[].slice.call(sl.querySelectorAll('.gpl-slide'));
  window.__gplSlide=0;
  var dw=document.getElementById('gpl-slider-dots');
  if(dw) dw.innerHTML=window.__gplSlides.map(function(_,i){return '<button class="gpl-sdot'+(i===0?' on':'')+'" onclick="gplSlideTo('+i+')" aria-label="Testimonial '+(i+1)+'"></button>';}).join('');
  // mobile: swipe sideways to advance
  sl.addEventListener('touchstart',function(e){ window.__gplTouchX=e.changedTouches[0].clientX; },{passive:true});
  sl.addEventListener('touchend',function(e){ var dx=e.changedTouches[0].clientX-(window.__gplTouchX||0); if(Math.abs(dx)>40) gplSlideTo(window.__gplSlide+(dx<0?1:-1)); },{passive:true});
  gplSlideSchedule();
}
function gplSlideTo(i){
  var s=window.__gplSlides; if(!s||!s.length) return;
  window.__gplSlide=(i+s.length)%s.length;
  s.forEach(function(el,j){el.classList.toggle('on',j===window.__gplSlide);});
  document.querySelectorAll('.gpl-sdot').forEach(function(d,j){d.classList.toggle('on',j===window.__gplSlide);});
  gplSlideSchedule();
}
function gplSlideSchedule(){
  if(window.__gplSlideTimer) clearTimeout(window.__gplSlideTimer);
  var s=window.__gplSlides, cur=s&&s[window.__gplSlide]; if(!cur) return;
  var img=cur.querySelector('img');
  var basis=(img&&(img.naturalHeight||img.clientHeight))||500;   // taller review image = more words = longer read
  var delay=Math.min(13000,Math.max(4500,Math.round(basis*11)));
  window.__gplSlideTimer=setTimeout(function(){ gplSlideTo(window.__gplSlide+1); }, delay);
}

/* ================= FILTERS ================= */
let gplType='all', gplThroat='all';
function gplApply(){
  let visible=0;
  FAMILIES.forEach(fam=>{
    const el=document.getElementById('gpl-fam-'+fam.id);
    const typeOk = gplType==='all'||fam.type===gplType;
    let fv=0;
    el.querySelectorAll('.gpl-unit').forEach(u=>{
      const tOk = gplThroat==='all'||Number(u.dataset.throat)===Number(gplThroat);
      const show = typeOk&&tOk; u.style.display=show?'':'none'; if(show)fv++;
    });
    el.style.display=(typeOk&&fv>0)?'':'none'; if(typeOk&&fv>0)visible+=fv;
  });
  document.getElementById('gpl-noresult').style.display = visible>0?'none':'block';
}
function gplFilterType(t){
  gplType=t;
  document.querySelectorAll('.gpl-chip.type').forEach(c=>c.setAttribute('aria-pressed',String(c.dataset.type===t)));
  gplApply();
  document.getElementById('gpl-machines').scrollIntoView({behavior:'smooth',block:'start'});
}
function gplFilterThroat(n){
  gplThroat=n;
  document.querySelectorAll('.gpl-chip.throat').forEach(c=>c.setAttribute('aria-pressed',String(c.dataset.throat==String(n))));
  gplApply();
}

/* ================= MODALS ================= */
function gplOpen(id){const m=document.getElementById(id);m.classList.add('open');requestAnimationFrame(()=>m.classList.add('show'));document.body.style.overflow='hidden';}
function gplClose(id){const m=document.getElementById(id);m.classList.remove('show');setTimeout(()=>{m.classList.remove('open');document.body.style.overflow='';if(id==='gpl-modal-features'){var b=document.getElementById('gpl-feat-body');if(b)b.innerHTML='';}},200);}
function gplZoom(url,alt){ var i=document.getElementById('gpl-zoom-img'); if(i){ i.src=url; i.alt=alt||''; } gplOpen('gpl-modal-zoom'); }
// Resolve the {{ASSET}} host token in runtime-injected HTML (the build only
// rewrites it in the static module HTML, not inside these JS strings).
function gplAsset(s){ return (s==null?'':String(s)).split('{{ASSET}}').join(window.GPL_BASE||''); }
function gplFeatures(famId){
  document.getElementById('gpl-feat-body').innerHTML = gplAsset(GPL_FEATURES[famId] || '');
  // Computerized modal is shared Statler/Ascend — open on the tier clicked.
  if(famId==='statler'||famId==='ascend') gplFeatTab(famId==='ascend'?1:0);
  gplOpen('gpl-modal-features');
}
// Scoped tab switch for the features modal (won't touch the pricing modal's global tabs).
function gplFeatTab(i){
  var b=document.getElementById('gpl-feat-body');
  b.querySelectorAll('.gpl-tab').forEach(t=>t.classList.toggle('on',Number(t.dataset.t)===i));
  b.querySelectorAll('.gpl-tabpanel').forEach((p,idx)=>p.classList.toggle('on',idx===i));
}
function gplSwapPhoto(btn,url){ var m=document.getElementById('gpl-detail-mainimg'); if(m)m.src=url; var p=btn.parentElement; if(p)p.querySelectorAll('.gpl-thumb').forEach(function(t){t.classList.toggle('on',t===btn)}); }
function gplDetail(fi,ui){
  const fam=FAMILIES[fi], u=fam.units[ui], sold=u.status==='sold';
  const incl=fam.included.map(i=>`<li><span class="ck">✓</span>${i}</li>`).join('');
  const rows=[['Family',`${fam.name} (${fam.typeLabel})`],['Throat',`${u.throat}″`],['Year',`${u.year}`],['Table',u.table],
    u.category?[u.retrofit?'Category':'Table style',`${u.category} — ${STYLE_NAME[u.category]||''}`]:null,
    u.retrofit?['Build','Factory retrofit — rebuilt head, new electronics']:null,
    u.region?['Availability',u.region]:null].filter(Boolean)
    .map(([k,v])=>`<div class="gpl-drow"><dt>${k}</dt><dd>${v}</dd></div>`).join('');
  const quilts=u.quilts?`<p class="muted" style="font-size:14px;margin-top:14px">At $${GPL_CFG.pricePerQuilt}/quilt, about <strong style="color:var(--char)">${u.quilts} quilts a month</strong> covers the payment.</p>`:'';
  const save=u.savings?`<span class="gpl-badge avail" style="font-size:13px;padding:4px 12px">Save ${gFmt(u.savings)} vs. new</span>`:'';
  // Per-unit photos: the sheet's `image` cell may hold one URL or several (comma/newline-separated).
  const photos=(u.image||'').split(/[\n,]/).map(s=>s.trim()).filter(Boolean);
  const mainPhoto=photos[0]||fam.image;
  const thumbs=photos.length>1?`<div class="gpl-thumbs">${photos.map((p,i)=>`<button class="gpl-thumb${i===0?' on':''}" onclick="gplSwapPhoto(this,'${p}')"><img src="${p}" alt="" loading="lazy"></button>`).join('')}</div>`:'';
  const cta=sold
    ? `<button class="gpl-btn gpl-btn--dark gpl-btn--block" onclick="gplClose('gpl-modal-detail');gplInquiry('Waitlist: ${u.throat}″ ${fam.name} show machine')">Join the waitlist</button>`
    : `<button class="gpl-btn gpl-btn--primary gpl-btn--block" onclick="gplClose('gpl-modal-detail');gplBuild(${fi},${ui})">Select Options</button>`;
  document.getElementById('gpl-detail-body').innerHTML=`
    <div class="gpl-badges" style="margin-bottom:8px"><span class="gpl-badge retro" style="background:rgba(45,45,45,.07);color:var(--gray)">${fam.typeLabel}</span> ${u.retrofit?catBadge(u.category):styleBadge(u.category)} ${retroBadge(u.retrofit)} ${sold?'<span class="gpl-badge sold">Sold</span>':'<span class="gpl-badge avail">1 available</span>'}</div>
    <h2 style="font-size:27px;margin-bottom:4px">${u.throat}″ ${fam.name} · ${u.year}</h2>
    <p class="muted" style="margin:0 0 4px">Stock #${u.id} · ${fam.tagline}</p>
    <div class="gpl-detail-img">
      ${mainPhoto ? `<img id="gpl-detail-mainimg" src="${mainPhoto}" alt="${u.throat}″ ${fam.name}" loading="lazy">` : `Photo of #${u.id}`}
    </div>
    ${thumbs}
    <p class="gpl-detail-cap">${photos.length ? `Actual photo${photos.length>1?'s':''} of stock #${u.id}.` : `Representative ${fam.name} photo — add this unit’s real photos via an <code>image</code> column in the sheet.`}</p>
    <div style="display:flex;flex-wrap:wrap;align-items:baseline;gap:16px;margin-bottom:14px">
      <span style="font-family:Raleway;font-weight:800;font-size:34px;color:var(--ink)" class="tnum">${u.price?gFmt(u.price):'—'}</span>
      ${u.monthly?`<span class="muted tnum">from $${u.monthly}/mo · 5–7 yr financing</span>`:''}
    </div>
    ${save?`<div style="margin-bottom:16px">${save}</div>`:''}
    <dl style="margin:0">${rows}</dl>${quilts}
    ${u.note?`<p class="muted" style="font-size:14px;font-style:italic;margin-top:12px">${u.note}</p>`:''}
    <div style="margin-top:22px;padding-top:20px;border-top:1px solid var(--line)">
      <p class="gpl-cap" style="margin:0 0 10px">Included with every ${fam.name}</p>
      <ul class="gpl-incl" style="display:grid;grid-template-columns:1fr 1fr;gap:2px 16px;margin-bottom:12px">${incl}</ul>
      <p style="margin:0 0 20px"><button class="gpl-link" onclick="gplWarranty()">View full warranty →</button></p>
      <div style="display:flex;flex-wrap:wrap;gap:10px">
        <div style="flex:1;min-width:150px">${cta}</div>
        ${GPL_FEATURES[fam.id]
          ? `<button class="gpl-btn gpl-btn--ghost" style="flex:1;min-width:150px" onclick="gplFeatures('${fam.id}')">See Features</button>`
          : `<a class="gpl-btn gpl-btn--ghost" style="flex:1;min-width:150px" href="tel:${GPL_CFG.phoneHref}">Call about it</a>`}
      </div>
    </div>`;
  gplOpen('gpl-modal-detail');
}

function gplPricing(tab){gplTab(typeof tab==='number'?tab:0);gplOpen('gpl-modal-pricing');}

function gplWarranty(){
  document.getElementById('gpl-warr-full').hidden=true;
  document.getElementById('gpl-warr-toggle').parentElement.style.display='';
  gplOpen('gpl-modal-warranty');
}
function gplWarrantyFull(){
  document.getElementById('gpl-warr-full').hidden=false;
  document.getElementById('gpl-warr-toggle').parentElement.style.display='none';
}

function gplResLabel(fam,u){
  const price=u.price?'$'+u.price.toLocaleString('en-US'):'POA';
  const mo=u.monthly?' or $'+u.monthly+' per month':'';
  if(u.retrofit) return `${u.throat}″ Pre-Loved Machine w/ New ${fam.name} Retrofit (${u.year}) — ${price}${mo}`;
  return `${u.throat}″ ${fam.name} ${u.year} — Pre-Loved — ${price}${mo}`;
}
// "Build Machine" — launch the configurator (new tab) pre-loaded for this
// pre-loved unit: generic Preloved product, with description + price overridden
// and the Pre-Loved quote template. See gammill-build-a-machine PRELOVED-DEEPLINK.md.
function gplBuild(fi,ui){
  const fam=FAMILIES[fi],u=fam.units[ui];
  // Retrofit units are graded by table-style CLASS (A/B/C); originals are DATED by year.
  // That maps to the configurator's mutually-exclusive preloved_class vs preloved_year.
  const graded = !!(u.retrofit && u.category);
  const yr = String(u.year==null?'':u.year).match(/\b(\d{4})\b/);   // 4-digit only (skip ranges like "2001–2009")
  // Quote line item — full, human, verbatim text exactly as it should read on the quote.
  const desc = graded
    ? `${u.throat}″ ${fam.name} Pre-Loved · Class ${u.category} · #${u.id}`
    : `${yr?yr[1]+' ':''}Pre-Loved ${fam.name} · ${u.throat}″ throat · #${u.id}`;
  const params=new URLSearchParams({
    template:'preloved',
    preloved_category:(u.dealCategory||'pre-loved'),   // pre-loved | paint-flaw | show | classroom (no sheet col yet → default)
    preloved_product_id:'1352372845',
    preloved_family:fam.id,                            // statler | vision | ascend
    preloved_price_cents:String((u.price||0)*100),
    preloved_description:desc                           // stays WHOLE — never stripped
  });
  if(graded)      params.set('preloved_class', u.category);   // year XOR class
  else if(yr)     params.set('preloved_year',  yr[1]);
  if(u.throat!=null && /^\d+$/.test(String(u.throat)))
    params.set('preloved_throat', String(u.throat));         // integer inches, when known
  window.open('https://buildamachine.gammilldealer.com/?'+params.toString(),'_blank','noopener');
}
// Legacy reserve/deposit modal — superseded by Build Machine, kept for reference.
function gplReserve(fi,ui){
  const fam=FAMILIES[fi],u=fam.units[ui];
  document.getElementById('gpl-res-machine').value=gplResLabel(fam,u);
  document.getElementById('gpl-res-demo').style.display='none';
  gplOpen('gpl-modal-reserve');
}
function gplDeposit(e){ e.preventDefault(); document.getElementById('gpl-res-demo').style.display='block'; return false; }

