  document.querySelectorAll('.gpl-tab').forEach(t=>t.classList.toggle('on',Number(t.dataset.t)===i));
  document.querySelectorAll('.gpl-tabpanel').forEach((p,idx)=>p.classList.toggle('on',idx===i));
