function gplInquiry(ctx){
  ctx = typeof ctx==='string'?ctx:'';
  const t=document.getElementById('gpl-iq-title'), c=document.getElementById('gpl-iq-ctx');
  if(t)t.style.display=''; if(c)c.style.display='';   // restore header (it gets hidden after a successful submit)
  if(ctx){ c.innerHTML=`About: <strong style="color:var(--char)">${ctx}</strong>. A Product Specialist will get back to you, usually same day.`;
    t.textContent = ctx.indexOf('Waitlist')===0?'Join the waitlist':'Reserve or request info'; }
  else { c.textContent='Tell us what you’re looking for. A Product Specialist will get back to you, usually same day.'; t.textContent='Reach a Product Specialist'; }
  gplLoadInquiryForm();
  gplOpen('gpl-modal-inquiry');
}
// Lazy-load HubSpot v2 and explicitly create the form into #gpl-iq-hsform (once).
// (Explicit create() is more reliable than auto-scan inside a modal that starts hidden.)
function gplLoadInquiryForm(){
  if(window.__gplIqFormDone) return;
  var create=function(){ if(window.__gplIqFormDone||!window.hbspt||!window.hbspt.forms) return; window.__gplIqFormDone=true;
    window.hbspt.forms.create({region:'na1',portalId:'20410581',formId:'f6616e36-207e-407d-b7c0-8a50ba671cab',target:'#gpl-iq-hsform',
      onFormSubmitted:function(){ var t=document.getElementById('gpl-iq-title'),c=document.getElementById('gpl-iq-ctx'); if(t)t.style.display='none'; if(c)c.style.display='none'; }
    }); };
  if(window.hbspt&&window.hbspt.forms){ create(); return; }
  if(window.__gplIqScript) return; window.__gplIqScript=true;
  var s=document.createElement('script'); s.src='https://js.hsforms.net/forms/embed/v2.js'; s.onload=create; document.body.appendChild(s);
}

function gplSubmit(e){
  e.preventDefault();
  const f=e.target, machine=f.machine.value||'General inquiry';
  const body=encodeURIComponent(`Machine: ${machine}\nName: ${f.name.value}\nEmail: ${f.email.value}\nPhone: ${f.phone.value}\n\n${f.message.value}`);
  window.location.href=`mailto:${GPL_CFG.email}?subject=${encodeURIComponent('Pre-Loved inquiry: '+machine)}&body=${body}`;
  return false;
}

document.addEventListener('keydown',e=>{ if(e.key==='Escape') ['gpl-modal-zoom','gpl-modal-pricing','gpl-modal-inquiry','gpl-modal-warranty','gpl-modal-reserve'].forEach(id=>{const m=document.getElementById(id);if(m){if(m.classList.contains('open'))gplClose(id);}}); });

/* ================= LIVE INVENTORY (Google Sheet) ================= */
function gplParseCSV(text){
  text=text.replace(/\r\n/g,'\n').replace(/\r/g,'\n');
  const rows=[]; let row=[], field='', inq=false, i=0;
  while(i<text.length){ const c=text[i];
    if(inq){ if(c==='"'){ if(text[i+1]==='"'){field+='"';i+=2;continue;} inq=false;i++;continue; } field+=c;i++;continue; }
    if(c==='"'){inq=true;i++;continue;}
    if(c===','){row.push(field);field='';i++;continue;}
    if(c==='\n'){row.push(field);rows.push(row);row=[];field='';i++;continue;}
    field+=c;i++;
  }
  if(field.length||row.length){row.push(field);rows.push(row);}
  return rows;
}
function gplLoadInventory(){
  if(!GPL_CFG.sheetCsv) return;
  fetch(GPL_CFG.sheetCsv,{cache:'no-store'})
    .then(r=>{ if(!r.ok) throw 0; return r.text(); })
    .then(text=>{
      const rows=gplParseCSV(text).filter(r=>r.length>1);
      if(rows.length<2) return;
      const head=rows[0].map(h=>h.trim().toLowerCase()); const idx=n=>head.indexOf(n);
      if(idx('id')<0||idx('family')<0||idx('status')<0) return;            // schema sanity
      const num=v=>{ v=(v||'').toString().replace(/[$,]/g,'').trim(); return v===''||isNaN(Number(v))?null:Number(v); };
      const byFam={};
      for(let r=1;r<rows.length;r++){ const row=rows[r]; const g=k=>{ const j=idx(k); return j<0?'':(row[j]||'').trim(); };
        if(g('status').toLowerCase()!=='active') continue;                  // sold/draft hidden
        const fam=g('family').toLowerCase();
        const u={ id:g('id'), throat:Number(g('throat'))||0, year:g('year'),
          price:num(g('price')), monthly:num(g('monthly')), table:g('table'),
          category:g('category')||null, retrofit:/^true$/i.test(g('retrofit')),
          savings:num(g('savings')), quilts:num(g('quilts')), region:g('region')||null,
          status:'available', note:g('note')||null, image:g('image')||null };
        (byFam[fam]=byFam[fam]||[]).push(u);
      }
      const total=Object.values(byFam).reduce((a,b)=>a+b.length,0);
      if(total<1) return;                                                   // never wipe to empty
      FAMILIES.forEach(f=>{ f.units = byFam[f.id] || []; });
      gplApplyMachineFilter();
    })
    .catch(()=>{ /* keep the baked-in snapshot */ });
}

